const { execSync } = require("node:child_process");

function getBranch(cwd = process.cwd()) {
	const out = execSync("git branch --show-current", {
		cwd,
		encoding: "utf8",
	}).trim();
	if (!out) {
		throw new Error("not on a branch (detached HEAD?) — pass --branch to override");
	}
	return out;
}

function sanitize(branch) {
	if (!branch || typeof branch !== "string") return "unknown";
	const slug = branch
		.toLowerCase()
		.replace(/[^a-z0-9-]+/g, "-")
		.replace(/-+/g, "-")
		.replace(/^-+|-+$/g, "")
		.slice(0, 30);
	return slug || "unknown";
}

module.exports = { getBranch, sanitize };

