const test = require("node:test");
const assert = require("node:assert/strict");
const {
	proxyPort,
	appKeySuffix,
	aliasHostname,
	desktopScheme,
	desktopTargetUrl,
	fnv1a,
} = require("../state");
const { sanitize } = require("../branch");

test("proxyPort: main pinned to 3024", () => {
	assert.equal(proxyPort("main"), 3024);
});

test("proxyPort: non-main is in [3030, 3999] and stable", () => {
	const p1 = proxyPort("spike");
	const p2 = proxyPort("spike");
	assert.equal(p1, p2);
	assert.ok(p1 >= 3030 && p1 <= 3999, `port ${p1} out of range`);
});

test("proxyPort: different slugs produce different ports (non-collision sample)", () => {
	const ports = new Set(["spike", "feat-foo", "feat-bar", "hotfix-1", "release-2"].map(proxyPort));
	assert.ok(ports.size >= 4, `expected mostly distinct, got ${ports.size}`);
});

test("appKeySuffix: main empty, others prefixed with dash", () => {
	assert.equal(appKeySuffix("main"), "");
	assert.equal(appKeySuffix("spike"), "-spike");
});

test("aliasHostname: main and branch", () => {
	assert.equal(aliasHostname("main"), "mfe.localhost");
	assert.equal(aliasHostname("spike"), "spike.mfe.localhost");
});

test("desktopScheme: main and branch", () => {
	assert.equal(desktopScheme("main"), "mfe-desktop");
	assert.equal(desktopScheme("spike"), "mfe-desktop-spike");
});

test("desktopTargetUrl: composes from alias + https port", () => {
	assert.equal(desktopTargetUrl("main"), "https://mfe.localhost:8443");
	assert.equal(desktopTargetUrl("spike"), "https://spike.mfe.localhost:8443");
});

test("sanitize: lowercases, replaces invalid, collapses, truncates", () => {
	assert.equal(sanitize("Feature/Some_Branch.Name"), "feature-some-branch-name");
	assert.equal(sanitize("---weird---"), "weird");
	assert.equal(sanitize(""), "unknown");
	assert.equal(sanitize(null), "unknown");
	assert.equal(sanitize("a".repeat(60)).length, 30);
});

test("fnv1a: deterministic + distinct for distinct inputs", () => {
	assert.equal(fnv1a("spike"), fnv1a("spike"));
	assert.notEqual(fnv1a("spike"), fnv1a("main"));
});

